// // This module implements a 32-entry register file with separate read and write operations. It provides two read ports (RSaddr_i and RTaddr_i) and one write port (RDaddr_i). The data to be written is provided via RDdata_i, and a control signal RegWrite_i determines when a write operation occurs on the falling edge of the clock signal clk_i.
module top_module(
    clk_i,
    RSaddr_i,
    RTaddr_i,
    RDaddr_i, 
    RDdata_i,
    RegWrite_i, 
    RSdata_o, 
    RTdata_o 
);input               clk_i;
input   [4:0]       RSaddr_i;
input   [4:0]       RTaddr_i;
input   [4:0]       RDaddr_i;
input   [31:0]      RDdata_i;
input               RegWrite_i;
output  [31:0]      RSdata_o; 
output  [31:0]      RTdata_o;


reg     [31:0]      register        [0:31];


assign  RSdata_o = register[RSaddr_i];
assign  RTdata_o = register[RTaddr_i];


always@(posedge clk_i) begin
    if(RegWrite_i)
        register[RDaddr_i] <= RDdata_i;
end

endmodule
